/* Dimension AI Studio — design tokens
 * Paleta neutra estilo ChatGPT/Claude. El color de marca TEI se reserva
 * para el logo y algunos enlaces; el resto de la UI usa escala de grises.
 */

:root {
  /* Superficies y fondos */
  --tei-bg:             #FFFFFF;
  --tei-bg-secondary:   #F7F7F8;   /* hovers, sidebars activos suaves */
  --tei-surface:        #FFFFFF;
  --tei-surface-raised: #FAFAFA;   /* cards, dialogs */

  /* Bordes */
  --tei-border:         #E5E5E5;
  --tei-border-strong:  #D4D4D4;

  /* Texto */
  --tei-text:           #1F1F1F;
  --tei-text-strong:    #0F0F0F;
  --tei-muted:          #6B7280;

  /* Acento primario (botones principales, foco). Monocromo alto contraste. */
  --tei-accent:         #1F1F1F;
  --tei-accent-hover:   #000000;
  --tei-accent-fg:      #FFFFFF;

  /* Marca Dimension TEI — solo logo, enlaces, highlights muy puntuales */
  --tei-brand:          #0064C0;
  --tei-brand-soft:     #42C2FF;

  /* Semántica (avisos de estado) */
  --tei-success:        #16A34A;
  --tei-warning:        #D97706;
  --tei-danger:         #DC2626;
  --tei-info:           #2563EB;

  /* Foco accesible */
  --tei-focus-ring:     #1F1F1F;

  /* Tipografía — fuentes locales servidas desde /public/fonts (sin Google Fonts).
   * Declaradas como @font-face en src/styles/fonts.css con unicode-range
   * para subset latin/latin-ext. */
  --tei-font-sans:      'Nunito', 'Segoe UI', system-ui, -apple-system, sans-serif;
  --tei-font-display:   var(--tei-font-sans);
  --tei-font-mono:      'JetBrains Mono', ui-monospace, SFMono-Regular, Menlo, Consolas, monospace;

  /* Overlay (modales, sheets) */
  --tei-overlay:        rgb(0 0 0 / 0.5);

  /* Botones flotantes sobre imágenes — siempre oscuros en ambos temas
   * para legibilidad sobre cualquier color de imagen. */
  --tei-image-overlay:        rgb(0 0 0 / 0.65);
  --tei-image-overlay-strong: rgb(0 0 0 / 0.85);
  --tei-image-overlay-fg:     #FFFFFF;

  /* Editor de recorte — máscara y handles, valores fijos para
   * legibilidad sobre cualquier imagen subyacente. */
  --tei-crop-mask:            rgb(0 0 0 / 0.45);
  --tei-crop-handle-bg:       #FFFFFF;
  --tei-crop-handle-border:   rgb(0 0 0 / 0.6);

  /* Radios */
  --tei-radius-sm: 6px;
  --tei-radius-md: 8px;
  --tei-radius-lg: 12px;
  --tei-radius-xl: 16px;

  /* Sombras sutiles */
  --tei-shadow-sm: 0 1px 2px rgb(0 0 0 / 0.04);
  --tei-shadow-md: 0 4px 16px rgb(0 0 0 / 0.06);
  --tei-shadow-lg: 0 12px 32px rgb(0 0 0 / 0.08);

  /* Transiciones */
  --tei-transition-quick: 150ms ease;
}

/* Tema oscuro — basado en la paleta de ChatGPT */
:root[data-theme="dark"] {
  --tei-bg:             #212121;
  --tei-bg-secondary:   #2F2F2F;
  --tei-surface:        #2F2F2F;
  --tei-surface-raised: #3A3A3A;

  --tei-border:         #3D3D3D;
  --tei-border-strong:  #525252;

  --tei-text:           #ECECEC;
  --tei-text-strong:    #FFFFFF;
  --tei-muted:          #9B9B9B;

  --tei-accent:         #FFFFFF;
  --tei-accent-hover:   #E5E5E5;
  --tei-accent-fg:      #0F0F0F;

  --tei-brand:          #42C2FF;
  --tei-brand-soft:     #0064C0;

  --tei-success:        #22C55E;
  --tei-warning:        #F59E0B;
  --tei-danger:         #F87171;
  --tei-info:           #60A5FA;

  --tei-focus-ring:     #FFFFFF;

  --tei-shadow-sm: 0 1px 2px rgb(0 0 0 / 0.25);
  --tei-shadow-md: 0 4px 16px rgb(0 0 0 / 0.35);
  --tei-shadow-lg: 0 12px 32px rgb(0 0 0 / 0.45);

  --tei-overlay:   rgb(0 0 0 / 0.7);
}

/* Reducir movimiento */
:root[data-reduced-motion="true"] {
  --tei-transition-quick: unset;
}

/* Fuentes corporativas — declaradas como @font-face nativas para poder
 * subsetear por unicode-range (latin / latin-ext) y minimizar el peso
 * descargado. Servidas desde /public/fonts (sin Google Fonts en runtime).
 *
 * Rangos copiados de la implementación oficial de Google Fonts. */

/* ─── Nunito ─────────────────────────────────────────────────────────── */

@font-face {
  font-family: 'Nunito';
  font-style: normal;
  font-weight: 400;
  font-display: swap;
  src: url('/fonts/nunito-latin-400-normal.woff2') format('woff2');
  unicode-range: U+0000-00FF, U+0131, U+0152-0153, U+02BB-02BC, U+02C6, U+02DA, U+02DC, U+0304, U+0308, U+0329, U+2000-206F, U+2074, U+20AC, U+2122, U+2191, U+2193, U+2212, U+2215, U+FEFF, U+FFFD;
}
@font-face {
